previewCss:
.darma-loader-darma-custom-574 {color: var(--loader-color, #ca8a04);
  --loader-secondary-color: var(--loader-secondary-color, #fde047);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 25px;
   aspect-ratio: 1;
   background:var(--loader-color, #ca8a04);
   animation: darma-loader-darma-custom-574-l1 1.5s infinite;
}
@keyframes darma-loader-darma-custom-574-l1  {
  0%, 100%{transform:translate(-30px,-30px);
  box-shadow: 0 0 var(--loader-color, #ca8a04), 0 0 var(--loader-color, #ca8a04)}
40% {transform:translate( 30px, 30px);
  box-shadow: -10px -10px var(--loader-color, #ca8a04),-20px -20px var(--loader-color, #ca8a04)}
50% {transform:translate( 30px, 30px);
  box-shadow: 0 0 var(--loader-color, #ca8a04), 0 0 var(--loader-color, #ca8a04)}
90% {transform:translate(-30px,-30px);
  box-shadow: 10px 10px var(--loader-color, #ca8a04), 20px 20px var(--loader-color, #ca8a04)}
}

